"""Scrapper tools"""

from langchain.tools import tool
from apify_client import ApifyClient
from openai import base_url
from configs import APIFY_API_TOKEN, JOB_SEARCH_QUERIES, LOCATION, SEACH_JOB_COUNT
from urllib.parse import urlencode


apify_client = ApifyClient(APIFY_API_TOKEN)

@tool
def linkedin_job_scrapper() -> list:
    """Scrape jobs listings from LinkedIn using Apify LinkedIn Job scrapper actor."""
    try:
        search_query = {
            "urls": get_linkedin_dynamic_url(),
            "count": int(SEACH_JOB_COUNT)
        }
        
        run = apify_client.actor("curious_coder/linkedin-jobs-scraper").call(run_input=search_query)
        results = apify_client.dataset(run["defaultDatasetId"]).list_items().items

        #results = mock_linkedin_job_scrapper() #remove this after testing
        print(f"Number of scrapped job listings from LinkedIn : {len(results)} \n")
        if not results:
            return [{"_error": "No results found", "_source": "LinkedIn"}]
        
        results = [{**job, "_source" : "LinkedIn"} for job in results]
        
        return results
    except Exception as e:
        return [{"_error": str(e), "_source": "LinkedIn"}]


def get_linkedin_dynamic_url() -> list[str] :
	"""Get dynamic linkedIn url with filter such as job tiles, location, etc"""
    
	base_url = "https://www.linkedin.com/jobs/search/?"
	linkedin_search_urls = []

	for query in JOB_SEARCH_QUERIES:
		params = {
			"keywords" : query,
			"location" : " ".join(LOCATION)
		}
		linkedin_search_urls.append(base_url + urlencode(params))
	
	return linkedin_search_urls



